ReportUtil = {}

local Supply = {
    health = 0,
    defense = 0,
    block = 0,
    bullet = 0
}

local function getXiyou(count)
    if count == 0 then
        return "0_0"
    elseif count <= 4 then
        return "1_4"
    elseif count <= 10 then
        return "5_10"
    else
        return "10a"
    end
end

local function getShiShi(count)
    if count == 0 then
        return "0_0"
    elseif count <= 2 then
        return "1_2"
    elseif count <= 5 then
        return "3_5"
    else
        return "5a"
    end
end

local function getChuanShuo(count)
    if count == 0 then
        return "0_0"
    elseif count <= 2 then
        return "1_2"
    else
        return "2a"
    end
end

local function getNum(count,maxCount)
    if count > maxCount then
        return maxCount .. "a"
    else
        return tostring(count)
    end
end

local function getTimeString(time)
    if time < 120 then
        return "0_2"
    elseif time < 180 then
        return "2_3"
    elseif time < 240 then
        return "3_4"
    elseif time < 300 then
        return "4_5"
    else
        return "5a"
    end
end

local function getPlayerNum(num)
    if num <= 15 then
        return "10_15"
    elseif num <= 20 then
        return "16_20"
    elseif num <= 25 then
        return "21_25"
    elseif num <= 30 then
        return "26_30"
    elseif num <= 35 then
        return "31_35"
    else
        return "36_40"
    end
end

local function getRunningTime(time)
    time = time - 30
    if time < 0 then
        return "airplane"
    end
    if time <= 15 then
        return "0_15"
    elseif time <= 45 then
        return "16_45"
    elseif time <= 90 then
        return "46_90"
    elseif time <= 135 then
        return "91_135"
    elseif time <= 180 then
        return "136_180"
    elseif time <= 250 then
        return "181_250"
    elseif time <= 320 then
        return "251_320"
    else
        return "320a"
    end
end

local function ifPickUpSupply(supplys)
    return TableUtil.isSameTable(supplys, Supply)
end

function ReportUtil:reportUpgrade(player)
    local parts = { "Upgrade", "PlayerLv" .. player.level, "ArmorLv" .. player.armor_level }
    GameAnalytics:design(player.userId, player.armor_level, parts)
end

function ReportUtil:reportDie(player)
    local parts_1 = { "g1053_playerDead", "KillNum", player.kills }
    GameAnalytics:design(player.userId, player.level, parts_1)

    local parts_2 = { "g1053_playerDead_Health", "SupplyNum_Hp" .. getNum(player.supplys.health, 5),
                    "SupplyNum_Aromr" .. getNum(player.supplys.defense, 6)}
    GameAnalytics:design(player.userId, player.level, parts_2)

    local parts_3 = { "g1053_playerDead_Weapon", "GunNum_xiyou" .. getXiyou(player.qualitySupplys.rare),
                    "GunNum_shishi" .. getShiShi(player.qualitySupplys.epic),
                    "GunNum_chuanshuo" .. getChuanShuo(player.qualitySupplys.legend)}
    GameAnalytics:design(player.userId, player.level, parts_3)

    local parts_4 = { "g1053_playerDead_Time", getRunningTime(RewardManager:getGameRunningTime())}
    GameAnalytics:design(player.userId, player.level, parts_4)

    local parts_5 = { "g1053_playerDead_Bullet", "SupplyNum_Bullet" .. getNum(player.supplys.bullet, 5),
                      "SupplyNum_Block" .. getNum(player.supplys.block, 4)}
    GameAnalytics:design(player.userId, player.level, parts_5)

    if ifPickUpSupply(player.supplys) then
        local parts_6 = { "g1053_playerDead_NoSupply"}
        GameAnalytics:design(player.userId, player.level, parts_6)
    end

end

function ReportUtil:reportGameStart(player, time, playerNum)
    local parts = { "g1053_gameStart", "WaitTime" .. getTimeString(time), "PlayerNum" .. getPlayerNum(playerNum)}
    GameAnalytics:design(player.userId, playerNum, parts)
end

return ReportUtil